import java.util.Scanner;

public class SecureBufferCopy {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Validate input length before copying to buffer
        if (input.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter string.");
            return;
        }

        char[] buffer = new char[10];
        input.getChars(0, input.length(), buffer, 0);

        System.out.println("Input copied to buffer: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
